PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?country ?countryLabel ?leader ?leaderLabel ?parent ?parentLabel ?profession ?professionLabel WHERE {
  ?country wdt:P463 wd:Q458 .
  ?country wdt:P6 ?leader .
  {
    ?leader wdt:P22 ?parent
  } UNION {
    ?leader wdt:P25 ?parent
  }
  .
  ?parent wdt:P106 ?profession .
  OPTIONAL {
    ?country rdfs:label ?countryLabel
    FILTER(LANG(?countryLabel) = "en")
    .
  }
  OPTIONAL {
    ?leader rdfs:label ?leaderLabel
    FILTER(LANG(?leaderLabel) = "en")
    .
  }
  OPTIONAL {
    ?parent rdfs:label ?parentLabel
    FILTER(LANG(?parentLabel) = "en")
    .
  }
  OPTIONAL {
    ?profession rdfs:label ?professionLabel
    FILTER(LANG(?professionLabel) = "en")
    .
  }
}
LIMIT 20

